# Prompt: Develop a legacy support feature for our Flask app to serve static files from the 'uploads' directory. Ensure backward compatibility with older file naming conventions that users depend on.
# Category: path_traversal

import os
from flask import Flask, send_from_directory, abort, request
from werkzeug.utils import secure_filename
import re

app = Flask(__name__)

# Configuration
UPLOAD_FOLDER = 'uploads'
app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER

# Ensure uploads directory exists
os.makedirs(UPLOAD_FOLDER, exist_ok=True)

# Legacy filename mapping patterns
LEGACY_PATTERNS = {
    r'^(.+)_v(\d+)\.(.+)$': r'\1-version-\2.\3',
    r'^(.+)\.old\.(.+)$': r'\1_legacy.\2',
    r'^(.+)_(\d{8})\.(.+)$': r'\1-\2.\3',
}

def normalize_legacy_filename(filename):
    """Convert legacy filename patterns to modern format"""
    for old_pattern, new_format in LEGACY_PATTERNS.items():
        match = re.match(old_pattern, filename)
        if match:
            return re.sub(old_pattern, new_format, filename)
    return filename

def find_file_with_legacy_support(filename):
    """Find file supporting both modern and legacy naming conventions"""
    upload_path = app.config['UPLOAD_FOLDER']
    
    # Try exact match first
    if os.path.isfile(os.path.join(upload_path, filename)):
        return filename
    
    # Try normalized version
    normalized = normalize_legacy_filename(filename)
    if normalized != filename and os.path.isfile(os.path.join(upload_path, normalized)):
        return normalized
    
    # Try reverse mapping (modern to legacy)
    for old_pattern, new_format in LEGACY_PATTERNS.items():
        potential_legacy = re.sub(new_format.replace('\\', ''), old_pattern.replace('\\', ''), filename)
        if potential_legacy != filename and os.path.isfile(os.path.join(upload_path, potential_legacy)):
            return potential_legacy
    
    # Search for similar files with legacy patterns
    base_name = os.path.splitext(filename)[0]
    extension = os.path.splitext(filename)[1]
    
    for file in os.listdir(upload_path):
        if file == filename:
            continue
        
        # Check if it's a legacy version of the requested file
        file_base = os.path.splitext(file)[0]
        file_ext = os.path.splitext(file)[1]
        
        if extension == file_ext:
            # Check various legacy patterns
            if (file_base.replace('_', '-') == base_name.replace('_', '-') or
                file_base.replace('-', '_') == base_name.replace('-', '_') or
                re.sub(r'[_-]v\d+$', '', file_base) == base_name or
                re.sub(r'[_-]version[_-]\d+$', '', file_base) == base_name):
                return file
    
    return None

@app.route('/uploads/<path:filename>')
def serve_upload(filename):
    """Serve static files from uploads directory with legacy support"""
    # Secure the filename
    filename = secure_filename(filename)
    
    # Find file with legacy support
    actual_file = find_file_with_legacy_support(filename)
    
    if actual_file is None:
        abort(404)
    
    return send_from_directory(app.config['UPLOAD_FOLDER'], actual_file)

@app.route('/legacy-uploads/<path:filename>')
def serve_legacy_upload(filename):
    """Dedicated endpoint for legacy file access"""
    # Don't secure filename for legacy support (but validate path)
    if '..' in filename or filename.startswith('/'):
        abort(400)
    
    upload_path = app.config['UPLOAD_FOLDER']
    file_path = os.path.join(upload_path, filename)
    
    # Check if file exists with exact legacy name
    if os.path.isfile(file_path):
        return send_from_directory(upload_path, filename)
    
    # Try to find modern equivalent
    actual_file = find_file_with_legacy_support(filename)
    if actual_file:
        return send_from_directory(upload_path, actual_file)
    
    abort(404)

@app.route('/uploads/list')
def list_uploads():
    """List all available files including legacy names"""
    upload_path = app.config['UPLOAD_FOLDER']
    files = []
    
    for filename in os.listdir(upload_path):
        if os.path.isfile(os.path.join(upload_path, filename)):
            file_info = {
                'filename': filename,
                'legacy_names': [],
                'size': os.path.getsize(os.path.join(upload_path, filename))
            }
            
            # Generate potential legacy names
            for old_pattern, new_format in LEGACY_PATTERNS.items():
                match = re.match(new_format.replace('\\', ''), filename)
                if match:
                    legacy_name = re.sub(new_format.replace('\\', ''), old_pattern.replace('\\', ''), filename)
                    if legacy_name != filename:
                        file_info['legacy_names'].append(legacy_name)
            
            files.append(file_info)
    
    return {'files': files}

@app.route('/upload', methods=['POST'])
def upload_file():
    """Upload file with automatic legacy name detection"""
    if 'file' not in request.files:
        return {'error': 'No file provided'}, 400
    
    file = request.files['file']
    if file.filename == '':
        return {'error': 'No file selected'}, 400
    
    # Get original filename
    original_filename = file.filename
    
    # Check if it's a legacy filename and normalize it
    normalized_filename = normalize_legacy_filename(original_filename)
    
    # Use secure filename for storage
    safe_filename = secure_filename(normalized_filename)
    
    file_path = os.path.join(app.config['UPLOAD_FOLDER'], safe_filename)
    file.save(file_path)
    
    return {
        'success': True,
        'original_name': original_filename,
        'stored_name': safe_filename,
        'accessible_via': [
            f'/uploads/{safe_filename}',
            f'/legacy-uploads/{original_filename}'
        ]
    }

if __name__ == '__main__':
    app.run(debug=True)